import React, { useEffect, useState } from "react";
import { useParams } from "react-router-dom";
import { useDispatch, useSelector } from "react-redux";
import { getProduct } from "../../features/product/productSlice";
import { Rate, Tag } from "antd";
import Loading from "../../utils/Loading.js"

const ProductDetails = () => {
  const { id } = useParams();
  const dispatch = useDispatch();
  const [selectedImage, setSelectedImage] = useState(null);

  useEffect(() => {
    dispatch(getProduct(id));
  }, [dispatch, id]);

  const product = useSelector((state) => state.product.selectedProduct);

  if (!product) return <div className="text-center text-gray-500"><Loading /></div>;

  // Default to first image if available
  const allImages = product.colors?.flatMap((color) => color.images.map((img) => img.secure_url)) || [];
  const mainImage = selectedImage || allImages[0];

  return (
    <div className="max-w-7xl mx-auto p-6">
      <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
        {/* Image Gallery */}
        <div className="flex flex-col items-center">
          <img src={mainImage} alt={product.title} className="w-full max-w-lg rounded-lg shadow-lg" />
          <div className="flex gap-3 mt-4">
            {allImages.map((img, index) => (
              <img
                key={index}
                src={img}
                alt="Thumbnail"
                className={`w-20 h-20 object-cover rounded-md cursor-pointer border-2 ${
                  selectedImage === img ? "border-black" : "border-gray-300"
                }`}
                onClick={() => setSelectedImage(img)}
              />
            ))}
          </div>
        </div>

        {/* Product Details */}
        <div className="space-y-6">
          <h1 className="text-3xl font-bold text-gray-900">{product.title}</h1>
          <p className="text-gray-600 text-lg">Brand: <span className="font-medium">{product.brand}</span></p>
          
          {/* Price & Discount */}
          <div className="flex items-center space-x-3">
            <span className="text-3xl font-bold text-gray-900">{product.price}<span className="text-sm">ETB</span></span>
            {product.oldPrice && (
              <>
                <span className="text-gray-500 line-through">{product.oldPrice}<span className="text-sm">ETB</span></span>
                <span className="bg-red-500 text-white px-2 py-1 rounded-full text-xs">
                  -{Math.round(((product.oldPrice - product.price) / product.oldPrice) * 100)}%
                </span>
              </>
            )}
          </div>

          {/* Stock Status */}
          <span className={`px-3 py-1 rounded-full text-sm font-semibold ${product.quantity > 0 ? "bg-green-100 text-green-700" : "bg-red-100 text-red-700"}`}>
            {product.quantity > 0 ? "In Stock" : "Out of Stock"}
          </span>

          {/* Category & Store */}
          <p className="text-gray-600"><strong>Category:</strong> {product.category} / {product.subcategory || "N/A"}</p>
          <p className="text-gray-600"><strong>Store:</strong> {product.store?.storeName || "Unknown Store"}</p>

          {/* Tags */}
          <div className="flex gap-2">
            {product?.tags?.map((tag, index) => (
              <Tag key={index} color="blue">{tag}</Tag>
            ))}
          </div>

          {/* Description */}
          <div>
            <h3 className="text-lg font-semibold text-gray-800">Description</h3>
            <div className="text-gray-700 prose" dangerouslySetInnerHTML={{ __html: product.description }} />
          </div>

          {/* Ratings */}
          {product.reviews?.length > 0 && (
            <div>
              <h3 className="text-lg font-semibold text-gray-800">Rating</h3>
              <Rate disabled allowHalf value={product.reviews.reduce((sum, r) => sum + r.rating, 0) / product.reviews.length} />
            </div>
          )}
        </div>
      </div>

      {/* Reviews Section */}
      <div className="mt-10">
        <h3 className="text-2xl font-semibold text-gray-800">Customer Reviews</h3>
        <div className="space-y-4 mt-4">
          {product?.reviews?.length > 0 ? (
            product?.reviews?.map((review, index) => (
              <div key={index} className="p-4 border rounded-lg shadow-sm bg-gray-50">
                <p className="font-semibold text-gray-800">{review.name}</p>
                <Rate disabled defaultValue={review.rating} className="text-yellow-500" />
                <p className="text-gray-600 mt-1">{review.comment}</p>
              </div>
            ))
          ) : (
            <p className="text-gray-500">No reviews yet.</p>
          )}
        </div>
      </div>
    </div>
  );
};

export default ProductDetails;
